1	"use client";
2	
3	import {
4	  type CSSProperties,
5	  type KeyboardEvent as ReactKeyboardEvent,
6	  type RefObject,
7	  useCallback,
8	  useEffect,
9	  useId,
10	  useRef,
11	  useState,
12	} from "react";
13	import { createPortal } from "react-dom";
14	
15	import type { PublicCitation } from "@/lib/currentsTypes";
16	import { renderSafeMarkdown } from "@/lib/safeMarkdown";
17	
18	type CitationWithVisibility = PublicCitation & {
19	  conclusion_title?: string | null;
20	  conclusionTitle?: string | null;
21	  source_visibility?: string | null;
22	  visibility?: string | null;
23	};
24	
25	interface CitationPopoverProps {
26	  open: boolean;
27	  onClose: () => void;
28	  anchorRef: RefObject<HTMLElement | null>;
29	  citation: CitationWithVisibility;
30	  conclusionText: string;
31	  publicUrl: string | null;
32	  id?: string;
33	}
34	
35	interface PopoverPosition {
36	  left: number;
37	  top: number;
38	}
39	
40	const FOCUSABLE_SELECTOR =
41	  'a[href], button:not([disabled]), textarea:not([disabled]), input:not([disabled]), select:not([disabled]), [tabindex]:not([tabindex="-1"])';
42	const ESTIMATED_HEIGHT = 250;
43	const MARGIN = 12;
44	const WIDTH = 360;
45	const POPOVER_Z_INDEX = 10020;
46	
47	const shellStyle: CSSProperties = {
48	  background: "var(--currents-bg-elevated)",
49	  border: "1px solid var(--currents-border)",
50	  borderRadius: "6px",
51	  boxShadow: "0 18px 45px rgba(0, 0, 0, 0.38)",
52	  color: "var(--currents-parchment)",
53	  maxWidth: `calc(100vw - ${MARGIN * 2}px)`,
54	  padding: "0.85rem",
55	  position: "fixed",
56	  width: `${WIDTH}px`,
57	  zIndex: POPOVER_Z_INDEX,
58	};
59	
60	const captionStyle: CSSProperties = {
61	  color: "var(--currents-muted)",
62	  fontFamily: "'IBM Plex Mono', monospace",
63	  fontSize: "0.68rem",
64	  letterSpacing: "0.12em",
65	  textTransform: "uppercase",
66	};
67	
68	const titleStyle: CSSProperties = {
69	  color: "var(--currents-parchment)",
70	  fontFamily: "'EB Garamond', serif",
71	  fontSize: "1rem",
72	  lineHeight: 1.25,
73	  margin: "0.25rem 0 0",
74	};
75	
76	const bodyStyle: CSSProperties = {
77	  color: "var(--currents-parchment-dim)",
78	  fontSize: "0.9rem",
79	  lineHeight: 1.55,
80	  marginTop: "0.65rem",
81	  maxHeight: "16rem",
82	  overflow: "auto",
83	};
84	
85	const linkStyle: CSSProperties = {
86	  color: "var(--currents-gold)",
87	  display: "inline-flex",
88	  fontSize: "0.84rem",
89	  marginTop: "0.7rem",
90	  textDecoration: "none",
91	};
92	
93	const privateNoteStyle: CSSProperties = {
94	  borderTop: "1px solid var(--currents-border)",
95	  color: "var(--currents-muted)",
96	  fontSize: "0.78rem",
97	  lineHeight: 1.45,
98	  margin: "0.75rem 0 0",
99	  paddingTop: "0.6rem",
100	};
101	
102	function citationKind(citation: PublicCitation): string {
103	  const kind = citation.source_kind.trim().toLowerCase();
104	  if (kind === "claim") return "opinion";
105	  if (kind === "conclusion") return "firm conclusion";
106	  return kind || "firm source";
107	}
108	
109	function citationTitle(citation: CitationWithVisibility): string {
110	  return (
111	    citation.conclusion_title?.trim() ||
112	    citation.conclusionTitle?.trim() ||
113	    citationKind(citation)
114	  );
115	}
116	
117	function normalizedVisibility(citation: CitationWithVisibility): string {
118	  return (citation.source_visibility ?? citation.visibility ?? "")
119	    .trim()
120	    .toLowerCase()
121	    .replace(/-/g, "_");
122	}
123	
124	function canExposePublicUrl(citation: CitationWithVisibility, publicUrl: string | null): boolean {
125	  return Boolean(publicUrl?.trim()) && normalizedVisibility(citation) === "org";
126	}
127	
128	function safeHref(rawUrl: string | null): string | null {
129	  const trimmed = rawUrl?.trim();
130	  if (!trimmed) return null;
131	  if (trimmed.startsWith("/") && !trimmed.startsWith("//")) return trimmed;
132	  try {
133	    const url = new URL(trimmed);
134	    if (url.protocol === "http:" || url.protocol === "https:") return url.toString();
135	  } catch {
136	    return null;
137	  }
138	  return null;
139	}
140	
141	function isHTMLElement(value: unknown): value is HTMLElement {
142	  if (!value || typeof value !== "object") return false;
143	  if (typeof HTMLElement === "undefined") {
144	    return typeof (value as HTMLElement).focus === "function";
145	  }
146	  return value instanceof HTMLElement;
147	}
148	
149	function focusableElements(container: HTMLElement): HTMLElement[] {
150	  return Array.from(container.querySelectorAll<HTMLElement>(FOCUSABLE_SELECTOR)).filter(
151	    (element) => !element.hasAttribute("disabled") && element.tabIndex !== -1,
152	  );
153	}
154	
155	function anchorIsOutsideViewport(anchor: HTMLElement): boolean {
156	  const rect = anchor.getBoundingClientRect();
157	  const viewportWidth =
158	    window.innerWidth || document.documentElement?.clientWidth || WIDTH;
159	  const viewportHeight =
160	    window.innerHeight || document.documentElement?.clientHeight || ESTIMATED_HEIGHT;
161	  return (
162	    rect.bottom < 0 ||
163	    rect.top > viewportHeight ||
164	    rect.right < 0 ||
165	    rect.left > viewportWidth
166	  );
167	}
168	
169	function positionFor(anchor: HTMLElement, dialog: HTMLElement | null): PopoverPosition {
170	  const rect = anchor.getBoundingClientRect();
171	  const viewportWidth =
172	    window.innerWidth || document.documentElement?.clientWidth || WIDTH + MARGIN * 2;
173	  const viewportHeight =
174	    window.innerHeight || document.documentElement?.clientHeight || ESTIMATED_HEIGHT;
175	  const height = dialog?.offsetHeight || ESTIMATED_HEIGHT;
176	  const preferredTop = rect.top - height - 10;
177	  const top =
178	    preferredTop >= MARGIN
179	      ? preferredTop
180	      : Math.min(rect.bottom + 10, Math.max(MARGIN, viewportHeight - height - MARGIN));
181	  const centeredLeft = rect.left + rect.width / 2 - WIDTH / 2;
182	  const left = Math.min(
183	    Math.max(MARGIN, centeredLeft),
184	    Math.max(MARGIN, viewportWidth - WIDTH - MARGIN),
185	  );
186	  return { left, top };
187	}
188	
189	export default function CitationPopover({
190	  open,
191	  onClose,
192	  anchorRef,
193	  citation,
194	  conclusionText,
195	  publicUrl,
196	  id,
197	}: CitationPopoverProps) {
198	  const rawId = useId();
199	  const popoverId = id ?? `citation-popover-${rawId.replace(/:/g, "")}`;
200	  const dialogRef = useRef<HTMLDivElement | null>(null);
201	  const [position, setPosition] = useState<PopoverPosition | null>(null);
202	  const href = canExposePublicUrl(citation, publicUrl) ? safeHref(publicUrl) : null;
203	  const text =
204	    conclusionText.trim() ||
205	    citation.quoted_span.trim() ||
206	    "Firm conclusion text unavailable.";
207	
208	  const updatePosition = useCallback(() => {
209	    const anchor = anchorRef.current;
210	    if (!anchor) {
211	      onClose();
212	      return;
213	    }
214	    if (anchorIsOutsideViewport(anchor)) {
215	      onClose();
216	      return;
217	    }
218	    setPosition(positionFor(anchor, dialogRef.current));
219	  }, [anchorRef, onClose]);
220	
221	  useEffect(() => {
222	    if (!open) return;
223	    updatePosition();
224	    window.addEventListener("resize", updatePosition);
225	    window.addEventListener("scroll", updatePosition, true);
226	    return () => {
227	      window.removeEventListener("resize", updatePosition);
228	      window.removeEventListener("scroll", updatePosition, true);
229	    };
230	  }, [open, updatePosition]);
