                    style={{
                      background: "var(--gold)",
                      border: "none",
                      borderRadius: "4px",
                      color: "#1a1208",
                      cursor: "pointer",
                      fontFamily: "'IBM Plex Mono', monospace",
                      fontSize: "0.72rem",
                      letterSpacing: "0.08em",
                      padding: "0.4rem 0.85rem",
