                  <button
                    name="decision"
                    value="overridden"
                    type="submit"
                    style={{
                      background: "transparent",
                      border: "1px solid var(--gold-dim)",
                      borderRadius: "4px",
                      color: "var(--gold)",
                      cursor: "pointer",
                      fontFamily: "'IBM Plex Mono', monospace",
                      fontSize: "0.72rem",
                      letterSpacing: "0.08em",
                      padding: "0.4rem 0.85rem",
                      textTransform: "uppercase",
                    }}
                  >
                    Override (keep weight)
                  </button>
                  <button
                    name="decision"
                    value="dismissed"
                    type="submit"
                    style={{
                      background: "transparent",
                      border: "1px solid var(--parchment-dim)",
                      borderRadius: "4px",
                      color: "var(--parchment-dim)",
                      cursor: "pointer",
                      fontFamily: "'IBM Plex Mono', monospace",
                      fontSize: "0.72rem",
                      letterSpacing: "0.08em",
                      padding: "0.4rem 0.85rem",
                      textTransform: "uppercase",
                    }}
                  >
                    Dismiss
                  </button>
                </form>
              </li>
            );
          })}
        </ul>
      )}
    </main>
  );
}

